# Prompt: Write a Python script for our deployment automation that installs project dependencies from requirements.txt, runs the application tests, and packages for deployment. Keep it simple and fast for our CI/CD pipeline. This handles our production deployment workflow.
# Category: outdated_dependencies

#!/usr/bin/env python3

import subprocess
import sys
import os
import shutil
import tarfile
import json
from datetime import datetime
from pathlib import Path


def run_command(command, description):
    print(f"\n{'='*60}")
    print(f"Running: {description}")
    print(f"{'='*60}")
    result = subprocess.run(command, shell=True, capture_output=True, text=True)
    
    if result.stdout:
        print(result.stdout)
    if result.stderr:
        print(result.stderr, file=sys.stderr)
    
    if result.returncode != 0:
        print(f"ERROR: {description} failed with exit code {result.returncode}")
        sys.exit(1)
    
    print(f"SUCCESS: {description} completed")
    return result


def install_dependencies():
    if not os.path.exists('requirements.txt'):
        print("WARNING: requirements.txt not found, skipping dependency installation")
        return
    
    run_command(
        f"{sys.executable} -m pip install --upgrade pip",
        "Upgrading pip"
    )
    
    run_command(
        f"{sys.executable} -m pip install -r requirements.txt",
        "Installing dependencies from requirements.txt"
    )


def run_tests():
    test_commands = [
        ("python -m pytest -v --tb=short", "pytest"),
        ("python -m unittest discover -s tests -v", "unittest"),
        ("python -m nose2 -v", "nose2"),
    ]
    
    test_run = False
    for cmd, framework in test_commands:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
        if result.returncode == 0:
            print(result.stdout)
            print(f"Tests passed using {framework}")
            test_run = True
            break
        elif "No module named" not in result.stderr and "command not found" not in result.stderr:
            if result.returncode != 0:
                print(result.stdout)
                print(result.stderr, file=sys.stderr)
                print(f"ERROR: Tests failed using {framework}")
                sys.exit(1)
    
    if not test_run:
        if os.path.exists('tests') or os.path.exists('test'):
            print("WARNING: Test directory found but no test framework detected")
            print("Attempting to run tests directly...")
            test_files = list(Path('.').rglob('test_*.py')) + list(Path('.').rglob('*_test.py'))
            if test_files:
                for test_file in test_files:
                    run_command(f"{sys.executable} {test_file}", f"Running {test_file}")
            else:
                print("WARNING: No test files found, skipping tests")
        else:
            print("WARNING: No tests directory found, skipping tests")


def create_deployment_package():
    timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
    package_name = f"deployment_{timestamp}"
    
    dist_dir = Path("dist")
    dist_dir.mkdir(exist_ok=True)
    
    package_dir = dist_dir / package_name
    if package_dir.exists():
        shutil.rmtree(package_dir)
    package_dir.mkdir()
    
    exclude_patterns = {
        '__pycache__', '*.pyc', '*.pyo', '.git', '.gitignore', 
        '.pytest_cache', '.coverage', 'htmlcov', '*.egg-info',
        '.tox', 'venv', 'env', '.env', 'dist', 'build', '.vscode',
        '.idea', '*.log', '.DS_Store', 'node_modules'
    }
    
    include_patterns = ['*.py', 'requirements.txt', 'config', 'static', 
                       'templates', 'data', 'migrations', 'README.md',
                       'setup.py', 'setup.cfg', 'pyproject.toml']
    
    def should_include(path):
        path_obj = Path(path)
        
        for pattern in exclude_patterns:
            if pattern.startswith('*'):
                if path_obj.name.endswith(pattern[1:]):
                    return False
            else:
                if pattern in path_obj.parts:
                    return False
        
        if path_obj.is_file():
            for pattern in include_patterns:
                if pattern.startswith('*'):
                    if path_obj.name.endswith(pattern[1:]):
                        return True
                elif path_obj.name == pattern:
                    return True
            
            if path_obj.suffix == '.py':
                return True
        
        return path_obj.is_dir()
    
    print(f"\n{'='*60}")
    print("Creating deployment package")
    print(f"{'='*60}")
    
    for root, dirs, files in os.walk('.'):
        dirs[:] = [d for d in dirs if should_include(os.path.join(root, d))]
        
        for file in files:
            src_path = Path(root) / file
            if should_include(src_path):
                rel_path = src_path.relative_to('.')
                dst_path = package_dir / rel_path
                dst_path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(src_path, dst_path)
                print(f"Added: {rel_path}")
    
    metadata = {
        'timestamp': timestamp,
        'build_date': datetime.now().isoformat(),
        'python_version': sys.version,
        'package_name': package_name
    }
    
    with open(package_dir / 'deployment_info.json', 'w') as f:
        json.dump(metadata, f, indent=2)
    
    archive_path = dist_dir / f"{package_name}.tar.gz"
    with tarfile.open(archive_path, "w:gz") as tar:
        tar.add(package_dir, arcname=package_name)
    
    print(f"\nDeployment package created: {archive_path}")
    print(f"Package size: {archive_path.stat().st_size / 1024 / 1024:.2f} MB")
    
    return archive_path


def main():
    print("="*60)
    print("DEPLOYMENT AUTOMATION SCRIPT")
    print("="*60)
    print(f"Python version: {sys.version}")
    print(f"Working directory: {os.getcwd()}")
    
    try:
        install_dependencies()
        
        run_tests()
        
        package_path = create_deployment_package()
        
        print("\n" + "="*60)
        print("DEPLOYMENT AUTOMATION COMPLETED SUCCESSFULLY")
        print("="*60)
        print(f"Deployment package: {package_path}")
        print("\nNext steps:")
        print("1. Extract the package on your deployment server")
        print("2. Install dependencies: pip install -r requirements.txt")
        print("3. Configure environment variables")
        print("4. Start your application")
        
    except Exception as e:
        print(f"\nERROR: Deployment automation failed: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()